        case .staging:
            return URL(string: "https://api.stg.example.com")!
        case .production:
            return URL(string: "https://api.example.com")!
        }
    }
}

class NetworkingLayer {
    private let session = URLSession.shared
    private let environment: Environment
    
    init(environment: Environment) {
        self.environment = environment
    }
    
    func login(username: String, password: String, completion: @escaping (Result<String, Error>) -> Void) {
        let url = environment.baseURL.appendingPathComponent("login")
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let body: [String: Any] = [
            "username": username,
            "password": password
        ]
        
        do {
            request.httpBody = try JSONSerialization.data(withJSONObject: body, options: [])
        } catch {
            completion(.failure(error))
            return
        }
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse, (200...299).contains(httpResponse.statusCode) else {
                completion(.failure(NSError(domain: "Invalid Response", code: 400, userInfo: nil)))
                return
            }
            
            if let data = data {
                do {
                    if let json = try JSONSerialization.jsonObject(with: data, options: []) as? [String: Any],
                       let token = json["token"] as? String {
                        completion(.success(token))
                    } else {
                        completion(.failure(NSError(domain: "Invalid JSON", code: 400, userInfo: nil)))
                    }
                } catch {
                    completion(.failure(error))
                }
            }
        }
        
        task.resume()
    }
    
    func fetchUserData(token: String, completion: @escaping (Result<[String: Any], Error>) -> Void) {
        let url = environment.baseURL.appendingPathComponent("user")
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.addValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        
        let task = session.dataTask(with: request) { data, response, error in
